const body = $input.first().json;

if (!body.tenant_slug) throw new Error('tenant_slug fehlt');
if (!body.query || body.query.length < 3) throw new Error('query zu kurz oder fehlt');

return [{ json: {
  tenant_slug: body.tenant_slug,
  query: body.query,
  session_id: body.session_id || `session-${Date.now()}`,
  bot_id: body.bot_id || null,
  top_k: body.top_k || 5,
  min_similarity: body.min_similarity || 0.55,
  doc_type: body.doc_type || null,
  model: body.model || 'llama3.2:3b',
  started_at: Date.now()
}}];

const chunks = $input.all().map(i => i.json);
const query = $('Validate Query').first().json.query;

if (chunks.length === 0) {
  return [{ json: {
    system_prompt: 'Du bist ein hilfreicher Assistent. Es wurden keine relevanten Informationen gefunden. Weise den Nutzer höflich darauf hin und bitte um eine konkretere Frage.',
    user_message: query,
    chunks_used: [],
    no_context: true
  }}];
}

const MAX_CHARS = 4000;
let contextParts = [];
let totalChars = 0;

for (const chunk of chunks) {
  const part = `[${chunk.document_title || 'Quelle'} | ${chunk.doc_type || ''} | Seite ${chunk.page_number || '?'} | Ähnlichkeit: ${(chunk.similarity * 100).toFixed(0)}%]:\n${chunk.content}`;
  if (totalChars + part.length > MAX_CHARS) break;
  contextParts.push(part);
  totalChars += part.length;
}

const context = contextParts.join('\n\n---\n\n');

return [{ json: {
  system_prompt: `Du bist ein hilfreicher Kundenservice-Assistent. Beantworte die Frage ausschließlich auf Basis der folgenden Quellen. Wenn die Antwort nicht in den Quellen enthalten ist, sage klar: "Dazu habe ich leider keine Information.". Antworte auf Deutsch, präzise und freundlich.\n\nQUELLEN:\n${context}`,
  user_message: query,
  chunks_used: chunks.map(c => ({ chunk_id: c.chunk_id, similarity: c.similarity, document_title: c.document_title }))
}}];

const llmResponse = $input.first().json;
const context = $('Build RAG Context').first().json;
const queryData = $('Validate Query').first().json;
const schema = $('Get Tenant Schema').first().json.schema_name;

const answer = llmResponse.message?.content || llmResponse.choices?.[0]?.message?.content || 'Keine Antwort erhalten';
const latencyMs = Date.now() - queryData.started_at;

return [{ json: {
  schema_name: schema,
  session_id: queryData.session_id,
  bot_id: queryData.bot_id,
  query: queryData.query,
  answer,
  chunks_used: context.chunks_used.map(c => c.chunk_id),
  model: queryData.model,
  latency_ms: latencyMs,
  sources: context.chunks_used
}}];
